syntax.postgresql:
-- Create an enum type
CREATE TYPE order_status AS ENUM ('pending', 'processing', 'shipped', 'delivered', 'cancelled');

-- Use it in a table
CREATE TABLE orders (
  id SERIAL PRIMARY KEY,
  status order_status NOT NULL DEFAULT 'pending'
);

-- Add a new value to an existing enum
ALTER TYPE order_status ADD VALUE 'refunded' AFTER 'cancelled';

syntax.mysql:
-- ENUM is defined inline in the column definition
CREATE TABLE orders (
  id INT AUTO_INCREMENT PRIMARY KEY,
  status ENUM('pending', 'processing', 'shipped', 'delivered', 'cancelled') NOT NULL DEFAULT 'pending'
);

syntax.mariadb:
-- ENUM is defined inline in the column definition
CREATE TABLE orders (
  id INT AUTO_INCREMENT PRIMARY KEY,
  status ENUM('pending', 'processing', 'shipped', 'delivered', 'cancelled') NOT NULL DEFAULT 'pending'
);

syntax.postgresql:
-- Create a composite type
CREATE TYPE address AS (
  street VARCHAR(200),
  city VARCHAR(100),
  state VARCHAR(50),
  zip_code VARCHAR(10),
  country VARCHAR(50)
);

-- Use in a table
CREATE TABLE users (
  id SERIAL PRIMARY KEY,
  username VARCHAR(50) NOT NULL,
  home_address address,
  work_address address
);

-- Insert data
INSERT INTO users (username, home_address)
VALUES ('john', ROW('123 Main St', 'Seoul', 'Seoul', '04524', 'KR'));

-- Access fields
SELECT username, (home_address).city FROM users;

-- Create a domain for email addresses
CREATE DOMAIN email_address AS VARCHAR(255)
  CHECK (VALUE ~* '^[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}$');

-- Create a domain for positive integers
CREATE DOMAIN positive_int AS INT
  CHECK (VALUE > 0);

-- Use domains in tables
CREATE TABLE users (
  id SERIAL PRIMARY KEY,
  email email_address NOT NULL,
  age positive_int
);

CREATE TABLE products (
  id SERIAL PRIMARY KEY,
  contact_email email_address,
  stock positive_int NOT NULL DEFAULT 0
);

-- Use built-in range types
CREATE TABLE events (
  id SERIAL PRIMARY KEY,
  name VARCHAR(100) NOT NULL,
  during TSTZRANGE NOT NULL
);

-- Insert a range
INSERT INTO events (name, during)
VALUES ('Conference', '[2025-06-01 09:00, 2025-06-03 18:00)');

-- Query: find events happening on a specific date
SELECT name FROM events
WHERE during @> '2025-06-02 12:00'::TIMESTAMPTZ;

-- Query: find overlapping events
SELECT a.name, b.name
FROM events a, events b
WHERE a.id < b.id AND a.during && b.during;

-- Create a custom range type
CREATE TYPE price_range AS RANGE (SUBTYPE = NUMERIC);

syntax.mysql:
-- Create a table with a SET column
CREATE TABLE users (
  id INT AUTO_INCREMENT PRIMARY KEY,
  username VARCHAR(50) NOT NULL,
  permissions SET('read', 'write', 'delete', 'admin') NOT NULL DEFAULT 'read'
);

-- Insert multiple values
INSERT INTO users (username, permissions) VALUES ('alice', 'read,write');
INSERT INTO users (username, permissions) VALUES ('bob', 'read,write,delete,admin');

-- Query: find users with 'admin' permission
SELECT username FROM users WHERE FIND_IN_SET('admin', permissions);

syntax.mariadb:
-- Create a table with a SET column
CREATE TABLE users (
  id INT AUTO_INCREMENT PRIMARY KEY,
  username VARCHAR(50) NOT NULL,
  permissions SET('read', 'write', 'delete', 'admin') NOT NULL DEFAULT 'read'
);

-- Insert multiple values
INSERT INTO users (username, permissions) VALUES ('alice', 'read,write');
INSERT INTO users (username, permissions) VALUES ('bob', 'read,write,delete,admin');

-- Query: find users with 'admin' permission
SELECT username FROM users WHERE FIND_IN_SET('admin', permissions);

-- MariaDB supports sequences (since 10.3)
CREATE SEQUENCE order_number_seq
  START WITH 1000
  INCREMENT BY 1
  NOCACHE;

-- Get the next value
SELECT NEXT VALUE FOR order_number_seq;

-- Use in a table
CREATE TABLE orders (
  id INT AUTO_INCREMENT PRIMARY KEY,
  order_number INT NOT NULL DEFAULT NEXT VALUE FOR order_number_seq
);

syntax.postgresql:
-- Create a table with array columns
CREATE TABLE products (
  id SERIAL PRIMARY KEY,
  name VARCHAR(100) NOT NULL,
  tags TEXT[] NOT NULL DEFAULT '{}',
  scores INT[]
);

-- Insert with array values
INSERT INTO products (name, tags, scores)
VALUES ('Keyboard', ARRAY['electronics', 'peripherals', 'input'], ARRAY[85, 92, 78]);

-- Query: find products with a specific tag
SELECT name FROM products WHERE 'electronics' = ANY(tags);

-- Query: find products containing all specified tags
SELECT name FROM products WHERE tags @> ARRAY['electronics', 'peripherals'];

-- Access array element (1-indexed)
SELECT name, tags[1] AS first_tag FROM products;
